import type { FC } from 'react';
import React from 'react';

import { classNames } from '../../helpers/classnames';
import { Popover } from '../Popover';
import type { TooltipProps } from './Tooltip.types';
import { TooltipContent } from './TooltipContent';

// TODO: описать SEO в доке
export const Tooltip: FC<TooltipProps> = ({
	title,
	disableHover,
	triggerMode = 'hover',
	closeMode = 'auto',
	className,
	popoverRootClassName,
	portalClassName,
	children,
	open,
	dataTestId = 'Tooltip',
	attachToChildren = false,
	placement,
	'aria-describedby': ariaDescribedBy,
	transitionDuration = { enter: 400, exit: 200 },
}) => (
	<Popover
		open={open}
		popoverClassName={classNames(popoverRootClassName)}
		portalClassName={classNames(portalClassName)}
		disableHover={disableHover}
		triggerMode={triggerMode}
		closeMode={closeMode}
		content={<TooltipContent title={title} className={className} />}
		dataTestId={dataTestId}
		attachToChildren={attachToChildren}
		placement={placement}
		aria-describedby={ariaDescribedBy}
		transitionDuration={transitionDuration}
	>
		{children}
	</Popover>
);
